import jsPDF from "jspdf";

// ─── Embedded images (base64) ───────────────────────────────────────────────
const SIGNATURE_IMG = "data:image/png;base64,";
const LOGO_IMG = "data:image/png;base64,";

// ─── Assessment name mapping ────────────────────────────────────────────────
const ASSESSMENT_NAMES: Record<string, string> = {
  litmus: "Litmus Test",
  johari_window: "CLEAR Test",
  career_dna: "Career DNA Profiler",
  career_compass: "Career Compass",
  metacognition_test: "Thinking & Expression Skills Test",
};

interface InvoicePayment {
  _id: string;
  amount: number;
  final_amount: number;
  discount_amount?: number;
  gst_applicable?: boolean;
  gst_amount?: number;
  razorpay_payment_id?: string | null;
  status: string;
  created_at: string;
}

interface InvoiceUser {
  name: string;
  email: string;
  mobile?: string;
  state?: string;
  city?: string;
  country?: string;
}

interface InvoiceOptions {
  payment: InvoicePayment;
  user: InvoiceUser;
  appId: string;
}

function numberToWords(num: number): string {
  if (num === 0) return "Zero";
  const ones = ["", "One", "Two", "Three", "Four", "Five", "Six", "Seven", "Eight", "Nine",
    "Ten", "Eleven", "Twelve", "Thirteen", "Fourteen", "Fifteen", "Sixteen", "Seventeen", "Eighteen", "Nineteen"];
  const tens = ["", "", "Twenty", "Thirty", "Forty", "Fifty", "Sixty", "Seventy", "Eighty", "Ninety"];

  function convert(n: number): string {
    if (n < 20) return ones[n];
    if (n < 100) return tens[Math.floor(n / 10)] + (n % 10 ? " " + ones[n % 10] : "");
    if (n < 1000) return ones[Math.floor(n / 100)] + " Hundred" + (n % 100 ? " " + convert(n % 100) : "");
    if (n < 100000) return convert(Math.floor(n / 1000)) + " Thousand" + (n % 1000 ? " " + convert(n % 1000) : "");
    if (n < 10000000) return convert(Math.floor(n / 100000)) + " Lakh" + (n % 100000 ? " " + convert(n % 100000) : "");
    return convert(Math.floor(n / 10000000)) + " Crore" + (n % 10000000 ? " " + convert(n % 10000000) : "");
  }

  const rupees = Math.floor(num);
  const paise = Math.round((num - rupees) * 100);
  let result = convert(rupees) + " Rupees";
  if (paise > 0) result += " and " + convert(paise) + " Paise";
  return result + " Only";
}

export function generateInvoice({ payment, user, appId }: InvoiceOptions) {
  const doc = new jsPDF("p", "mm", "a4");
  const W = 210;
  const margin = 15;
  const contentW = W - 2 * margin;
  const date = new Date(payment.created_at);
  const dateStr = date.toLocaleDateString("en-IN", { day: "2-digit", month: "2-digit", year: "numeric" });
  const invoiceNo = `ADM/${payment._id.slice(-6).toUpperCase()}/${date.getFullYear()}-${String(date.getFullYear() + 1).slice(-2)}`;
  const assessmentName = ASSESSMENT_NAMES[appId] || appId;
  const isGujarat = (user.state || "").toLowerCase().includes("gujarat");
  const gstApplicable = payment.gst_applicable && (payment.gst_amount || 0) > 0;
  const gstAmount = payment.gst_amount || 0;

  let cgst = 0, sgst = 0, igst = 0;
  if (gstApplicable) {
    if (isGujarat) {
      cgst = Math.round((gstAmount / 2) * 100) / 100;
      sgst = Math.round((gstAmount - cgst) * 100) / 100;
    } else {
      igst = gstAmount;
    }
  }

  const discountAmount = payment.discount_amount || 0;
  const subTotal = payment.amount - discountAmount;

  // Colors
  const navy = [26, 35, 75] as const;
  const darkGray = [55, 65, 81] as const;
  const lightGray = [156, 163, 175] as const;
  const accentBlue = [37, 99, 235] as const;

  let y = margin;

  // ─── HEADER ──────────────────────────────────────────────────────────────────
  doc.setFillColor(255, 255, 255);
  doc.rect(0, 0, W, 42, "F");
  // Bottom border line for header
  doc.setDrawColor(26, 35, 75);
  doc.setLineWidth(0.5);
  doc.line(0, 42, W, 42);

  doc.setTextColor(26, 35, 75);
  doc.setFontSize(22);
  doc.setFont("helvetica", "bold");
  doc.text("INVOICE CUM RECEIPT", margin, 20);

  doc.setFontSize(9);
  doc.setFont("helvetica", "normal");
  doc.setTextColor(55, 65, 81);
  doc.text(`Invoice No: ${invoiceNo}`, margin, 30);
  doc.text(`Date: ${dateStr}`, margin, 36);

  // Logo in header (right side)
  doc.addImage(LOGO_IMG, "PNG", W - margin - 50, 14, 50, 17);

  y = 52;

  // ─── BILL TO / BILL BY ──────────────────────────────────────────────────────
  const colW = contentW / 2 - 5;
  const billBoxH = 58; // Increased height to fit GST No inside

  // Bill To
  doc.setFillColor(245, 247, 250);
  doc.roundedRect(margin, y, colW, billBoxH, 3, 3, "F");
  doc.setTextColor(...accentBlue);
  doc.setFontSize(8);
  doc.setFont("helvetica", "bold");
  doc.text("BILL TO", margin + 6, y + 8);

  doc.setTextColor(...navy);
  doc.setFontSize(10);
  doc.text(user.name, margin + 6, y + 16);

  doc.setTextColor(...darkGray);
  doc.setFontSize(8);
  doc.setFont("helvetica", "normal");
  let billToY = y + 23;
  const cityState = [user.city, user.state, user.country].filter(Boolean).join(", ");
  if (cityState) {
    doc.text(cityState, margin + 6, billToY);
    billToY += 6;
  }
  if (user.email) {
    doc.text(user.email, margin + 6, billToY);
    billToY += 6;
  }
  if (user.mobile) {
    doc.text(`+91 ${user.mobile}`, margin + 6, billToY);
  }

  // Bill By
  const billByX = margin + colW + 10;
  doc.setFillColor(245, 247, 250);
  doc.roundedRect(billByX, y, colW, billBoxH, 3, 3, "F");
  doc.setTextColor(...accentBlue);
  doc.setFontSize(8);
  doc.setFont("helvetica", "bold");
  doc.text("BILL BY", billByX + 6, y + 8);

  doc.setTextColor(...navy);
  doc.setFontSize(10);
  doc.text("KAREER Studio", billByX + 6, y + 16);

  doc.setTextColor(...darkGray);
  doc.setFontSize(8);
  doc.setFont("helvetica", "normal");
  doc.text("Suite #303, Rajshree Center, Opp. Hotel Effotel,", billByX + 6, y + 23);
  doc.text("Near Kalaghoda, Sayajigunj, Vadodara - 390020", billByX + 6, y + 29);
  doc.text("Gujarat, India", billByX + 6, y + 35);
  doc.text("hello@kareerstudio.com | +91 7777 07 1711", billByX + 6, y + 41);
  doc.text("PAN: AAZFK7452R", billByX + 6, y + 47);
  doc.text("GST No: ASDFGHJKL", billByX + 6, y + 53);

  y += billBoxH + 8;

  // ─── ITEMS TABLE with proper borders ─────────────────────────────────────────
  const col1W = 70;  // Item
  const col2W = 20;  // Unit
  const col3W = 30;  // Rate
  const col4W = 30;  // Discount
  const col5W = contentW - col1W - col2W - col3W - col4W; // Sub Total
  const rowH = 10;

  // Table Header
  doc.setFillColor(26, 35, 75);
  doc.rect(margin, y, contentW, rowH, "F");
  doc.setDrawColor(26, 35, 75);
  doc.setLineWidth(0.3);
  doc.rect(margin, y, contentW, rowH, "S");

  doc.setTextColor(255, 255, 255);
  doc.setFontSize(10);
  doc.setFont("helvetica", "bold");

  let cx = margin;
  doc.text("Item", cx + 4, y + 7);
  cx += col1W;
  doc.line(cx, y, cx, y + rowH);
  doc.text("Unit", cx + 4, y + 7);
  cx += col2W;
  doc.line(cx, y, cx, y + rowH);
  doc.text("Rate", cx + 4, y + 7);
  cx += col3W;
  doc.line(cx, y, cx, y + rowH);
  doc.text("Discount", cx + 4, y + 7);
  cx += col4W;
  doc.line(cx, y, cx, y + rowH);
  doc.text("Sub Total", cx + 4, y + 7);

  y += rowH;

  // Item Row with borders
  doc.setFillColor(250, 251, 252);
  doc.rect(margin, y, contentW, rowH, "F");
  doc.setDrawColor(200, 200, 200);
  doc.setLineWidth(0.2);
  doc.rect(margin, y, contentW, rowH, "S");

  doc.setTextColor(...navy);
  doc.setFontSize(10);
  doc.setFont("helvetica", "normal");

  cx = margin;
  doc.text(assessmentName, cx + 4, y + 7);
  cx += col1W;
  doc.line(cx, y, cx, y + rowH);
  doc.text("1", cx + 8, y + 7);
  cx += col2W;
  doc.line(cx, y, cx, y + rowH);
  doc.text(`${payment.amount.toFixed(2)}`, cx + 4, y + 7);
  cx += col3W;
  doc.line(cx, y, cx, y + rowH);
  doc.text(`${discountAmount.toFixed(2)}`, cx + 4, y + 7);
  cx += col4W;
  doc.line(cx, y, cx, y + rowH);
  doc.text(`${subTotal.toFixed(2)}`, cx + 4, y + 7);

  y += rowH + 3;

  // ─── TOTALS SECTION with borders ─────────────────────────────────────────────
  const totalsTableX = margin + contentW - 80;
  const totalsTableW = 80;
  const labelW = 50;
  const valW = totalsTableW - labelW;
  const totRowH = 8;

  doc.setDrawColor(200, 200, 200);
  doc.setLineWidth(0.2);
  doc.setTextColor(...darkGray);
  doc.setFontSize(10);
  doc.setFont("helvetica", "normal");

  // Row: Total Discount
  doc.rect(totalsTableX, y, labelW, totRowH, "S");
  doc.rect(totalsTableX + labelW, y, valW, totRowH, "S");
  doc.text("Total Discount", totalsTableX + 3, y + 5.5);
  doc.text(`${discountAmount.toFixed(2)}`, totalsTableX + totalsTableW - 3, y + 5.5, { align: "right" });
  y += totRowH;

  // Row: Sub Total Amount
  doc.rect(totalsTableX, y, labelW, totRowH, "S");
  doc.rect(totalsTableX + labelW, y, valW, totRowH, "S");
  doc.text("Sub Total Amount", totalsTableX + 3, y + 5.5);
  doc.text(`${subTotal.toFixed(2)}`, totalsTableX + totalsTableW - 3, y + 5.5, { align: "right" });
  y += totRowH;

  if (gstApplicable) {
    if (isGujarat) {
      doc.rect(totalsTableX, y, labelW, totRowH, "S");
      doc.rect(totalsTableX + labelW, y, valW, totRowH, "S");
      doc.text("CGST (9%)", totalsTableX + 3, y + 5.5);
      doc.text(`${cgst.toFixed(2)}`, totalsTableX + totalsTableW - 3, y + 5.5, { align: "right" });
      y += totRowH;

      doc.rect(totalsTableX, y, labelW, totRowH, "S");
      doc.rect(totalsTableX + labelW, y, valW, totRowH, "S");
      doc.text("SGST (9%)", totalsTableX + 3, y + 5.5);
      doc.text(`${sgst.toFixed(2)}`, totalsTableX + totalsTableW - 3, y + 5.5, { align: "right" });
      y += totRowH;
    } else {
      doc.rect(totalsTableX, y, labelW, totRowH, "S");
      doc.rect(totalsTableX + labelW, y, valW, totRowH, "S");
      doc.text("IGST (18%)", totalsTableX + 3, y + 5.5);
      doc.text(`${igst.toFixed(2)}`, totalsTableX + totalsTableW - 3, y + 5.5, { align: "right" });
      y += totRowH;
    }
  } else {
    // IGST row
    doc.rect(totalsTableX, y, labelW, totRowH, "S");
    doc.rect(totalsTableX + labelW, y, valW, totRowH, "S");
    doc.text("IGST", totalsTableX + 3, y + 5.5);
    doc.text("0", totalsTableX + totalsTableW - 3, y + 5.5, { align: "right" });
    y += totRowH;

    // CGST row
    doc.rect(totalsTableX, y, labelW, totRowH, "S");
    doc.rect(totalsTableX + labelW, y, valW, totRowH, "S");
    doc.text("CGST", totalsTableX + 3, y + 5.5);
    doc.text("0", totalsTableX + totalsTableW - 3, y + 5.5, { align: "right" });
    y += totRowH;

    // SGST row
    doc.rect(totalsTableX, y, labelW, totRowH, "S");
    doc.rect(totalsTableX + labelW, y, valW, totRowH, "S");
    doc.text("SGST", totalsTableX + 3, y + 5.5);
    doc.text("0", totalsTableX + totalsTableW - 3, y + 5.5, { align: "right" });
    y += totRowH;
  }

  // Total Amount row (dark)
  doc.setFillColor(26, 35, 75);
  doc.rect(totalsTableX, y, totalsTableW, totRowH + 2, "F");
  doc.setTextColor(255, 255, 255);
  doc.setFontSize(10);
  doc.setFont("helvetica", "bold");
  doc.text("Total Amount", totalsTableX + 3, y + 6.5);
  doc.text(`${payment.final_amount.toFixed(2)}`, totalsTableX + totalsTableW - 3, y + 6.5, { align: "right" });

  // Amount in words (left aligned, same row)
  doc.setTextColor(...lightGray);
  doc.setFontSize(10);
  doc.setFont("helvetica", "italic");
  doc.text(numberToWords(payment.final_amount), margin, y + 6.5);

  y += totRowH + 10;

  // ─── GST BREAKDOWN TABLE ─────────────────────────────────────────────────────
  if (gstApplicable) {
    const gstColW = contentW / (isGujarat ? 3 : 2);
    const gstRowH = 9;

    // Header
    doc.setFillColor(245, 247, 250);
    doc.setDrawColor(200, 200, 200);
    doc.setLineWidth(0.2);
    doc.rect(margin, y, contentW, gstRowH, "FD");
    doc.setTextColor(...navy);
    doc.setFontSize(10);
    doc.setFont("helvetica", "bold");
    doc.text("Taxable Value", margin + 4, y + 6);
    if (isGujarat) {
      doc.line(margin + gstColW, y, margin + gstColW, y + gstRowH);
      doc.text("CGST (9%)", margin + gstColW + 4, y + 6);
      doc.line(margin + gstColW * 2, y, margin + gstColW * 2, y + gstRowH);
      doc.text("SGST (9%)", margin + gstColW * 2 + 4, y + 6);
    } else {
      doc.line(margin + gstColW, y, margin + gstColW, y + gstRowH);
      doc.text("IGST (18%)", margin + gstColW + 4, y + 6);
    }

    y += gstRowH;

    // Data row
    doc.rect(margin, y, contentW, gstRowH, "S");
    doc.setFont("helvetica", "normal");
    doc.setTextColor(...darkGray);
    doc.text(`${subTotal.toFixed(2)}`, margin + 4, y + 6);
    if (isGujarat) {
      doc.line(margin + gstColW, y, margin + gstColW, y + gstRowH);
      doc.text(`${cgst.toFixed(2)}`, margin + gstColW + 4, y + 6);
      doc.line(margin + gstColW * 2, y, margin + gstColW * 2, y + gstRowH);
      doc.text(`${sgst.toFixed(2)}`, margin + gstColW * 2 + 4, y + 6);
    } else {
      doc.line(margin + gstColW, y, margin + gstColW, y + gstRowH);
      doc.text(`${igst.toFixed(2)}`, margin + gstColW + 4, y + 6);
    }
    y += gstRowH + 6;
  }

  // ─── BANK DETAILS ────────────────────────────────────────────────────────────
  doc.setFillColor(245, 247, 250);
  doc.roundedRect(margin, y, contentW, 32, 3, 3, "F");
  doc.setTextColor(...accentBlue);
  doc.setFontSize(8);
  doc.setFont("helvetica", "bold");
  doc.text("PAYMENT DETAILS", margin + 6, y + 8);

  doc.setTextColor(...darkGray);
  doc.setFontSize(7.5);
  doc.setFont("helvetica", "normal");
  doc.text("Beneficiary: KAREER Studio", margin + 6, y + 15);
  doc.text("Axis Bank Current Account Number: 923020061117712", margin + 6, y + 21);
  doc.text("SAVLI BRANCH, VADODARA  |  IFSC: UTIB0004011  |  SWIFT: AXISINBB013", margin + 6, y + 27);

  doc.text("UPI ID: 7777071711@okbizaxis", margin + contentW - 65, y + 15);
  doc.text("UPI Number: +91 7777 07 1711", margin + contentW - 65, y + 21);

  y += 40;

  // ─── TERMS & CONDITIONS ──────────────────────────────────────────────────────
  doc.setTextColor(...navy);
  doc.setFontSize(8);
  doc.setFont("helvetica", "bold");
  doc.text("TERMS & CONDITIONS", margin, y);
  y += 6;

  doc.setTextColor(...darkGray);
  doc.setFontSize(7);
  doc.setFont("helvetica", "normal");

  const terms = [
    "1. Cheques subject to realization.",
    "2. Fees once paid are not refundable.",
  ];

  terms.forEach((term) => {
    doc.text(term, margin, y);
    y += 5;
  });

  // ─── SIGNATURE (right-aligned, positioned above footer) ─────────────────────
  const sigX = W - margin;
  const footerY = 285;
  // Position signature block so it ends just above footer
  const sigStartY = footerY - 33;

  doc.setTextColor(...navy);
  doc.setFontSize(9);
  doc.setFont("helvetica", "bold");
  doc.text("For ADMITra", sigX, sigStartY, { align: "right" });

  // Signature image
  doc.addImage(SIGNATURE_IMG, "PNG", sigX - 26, sigStartY + 2, 32, 16);

  doc.setFontSize(9);
  doc.setFont("helvetica", "bold");
  doc.setTextColor(...navy);
  doc.text("Makrand Bhatt", sigX, sigStartY + 22, { align: "right" });
  doc.setFontSize(7);
  doc.setFont("helvetica", "normal");
  doc.setTextColor(...lightGray);
  doc.text("Authorized Signatory", sigX, sigStartY + 27, { align: "right" });

  // ─── FOOTER ──────────────────────────────────────────────────────────────────
  doc.setFillColor(26, 35, 75);
  doc.rect(0, footerY, W, 12, "F");
  doc.setTextColor(200, 200, 200);
  doc.setFontSize(7);
  doc.setFont("helvetica", "normal");
  doc.text(
    "Reg. Office: KAREER Studio, Suite #303, Rajshree Center, Opp. Hotel Effotel, Near Kalaghoda, Sayajigunj, Vadodara - 390020  |  hello@kareerstudio.com  |  +91 7777 07 1711",
    W / 2, footerY + 7,
    { align: "center" }
  );

  // Save
  const fileName = `Invoice_${invoiceNo.replace(/\//g, "_")}.pdf`;
  doc.save(fileName);
}
